mapper.select:
SELECT jr.request_id, jr.user_id, jr.team_id, jr.message, jr.status, jr.created_at, jr.reviewed_at, u.username, u.avatar, u.email FROM join_requests jr INNER JOIN users u ON jr.user_id = u.user_id
AND jr.team_id = #{teamId}
AND jr.status = #{status}
ORDER BY CASE jr.status WHEN 'pending' THEN 0 ELSE 1 END, jr.created_at DESC

SELECT COUNT(*) FROM join_requests
WHERE user_id = #{userId}
  AND team_id = #{teamId}
  AND status = 'pending'

SELECT jr.request_id, jr.user_id, jr.team_id, jr.message, jr.status, jr.created_at, jr.reviewed_at, t.name AS team_name FROM join_requests jr INNER JOIN teams t ON jr.team_id = t.team_id
AND jr.user_id = #{userId}
AND jr.status = #{status}
ORDER BY jr.created_at DESC
